#!/usr/bin/env python3
"""resonance_lsh_cache_sim — first end-to-end RESONANCE-LSH CACHE simulation.

THESIS ("sovereign sieve"): the rwkv7-0.4b final pre-lm_head hidden has a low-rank
RESONANCE SIGNATURE (sign-of-top-K-energy-dims). If a query's resonance signature
LSH-buckets to a PRECOMPUTED cache entry, we can serve the precomputed answer and
SKIP the ~195ms/token lm_head dot (the dot is 99.7% of the live per-token cost).

DESIGN (miss-not-lie):
  SEED  the cache with ONE phrasing per paraphrase group ("precomputed" entry;
        its "answer" = the group id).
  KEY   = sign(top-K energy dims) signature -> banded-LSH buckets. A query probes
        every band-bucket it lands in; union of seeds sharing >=1 band = candidates.
  VERIFY every candidate by FULL-hidden cosine >= tau. Best verified candidate is
        served. A candidate that fails verify = MISS (never a wrong answer).
  QUERY the REMAINING group phrasings (paraphrases, SHOULD hit their own group's
        seed) + all NOVEL singletons (SHOULD miss).

METRICS:
  (a) TRUE  hit-rate  = paraphrase queries that correctly hit their OWN group seed.
  (b) FALSE hit-rate  = queries served the WRONG group (para->other group) OR a
                        novel served any group. Post-verify this must be ~0
                        (the correctness gate).
  (c) tok/s-equivalent saved per hit = 195ms/token * answer_len tokens skipped.

Sweeps K (50/64/128) and tau to find the operating point that MAXIMIZES true-hit
while keeping false-hit ~0.
"""
import json
import itertools
import sys
import numpy as np

P = sys.argv[1] if len(sys.argv) > 1 else "/private/tmp/claude-501/-Users-buley-Documents-Code-monorepo/dab2040a-b9df-4f6b-8f0f-d96780b01544/scratchpad/resonance_acts.json"
DOT_MS_PER_TOKEN = 195.0   # measured live per-token lm_head-dot cost (from prior brick)

d = json.load(open(P))
recs = d["records"]
D = d["hidden_dim"]
X = np.array([r["activation"] for r in recs], dtype=np.float64)  # (N, D)
groups = [r["group"] for r in recs]
texts = [r["text"] for r in recs]
tok_len = [len(r["tokens"]) for r in recs]
N = len(recs)


def is_para(g):
    return g.startswith("g")


# ---- resonance signature: sign of the top-K energy dims (others -> 0) ---------
def signature(v, k):
    """Ternary signature over the whole D-vector: +1/-1 on the top-K energy dims,
    0 elsewhere. Returned as an int8 array of length D."""
    e = v * v
    idx = np.argsort(e)[::-1][:k]
    sig = np.zeros(D, dtype=np.int8)
    sig[idx] = np.sign(v[idx]).astype(np.int8)
    return sig, set(idx.tolist())


def cos(a, b):
    na, nb = np.linalg.norm(a), np.linalg.norm(b)
    if na == 0 or nb == 0:
        return 0.0
    return float(a @ b / (na * nb))


# Group the corpus. First phrasing of each paraphrase group = the SEED.
para_groups = {}
for i in range(N):
    g = groups[i]
    if is_para(g):
        para_groups.setdefault(g, []).append(i)

seed_idx = {g: members[0] for g, members in para_groups.items()}
seeds = list(seed_idx.values())
seed_set = set(seeds)

# Queries = every non-seed paraphrase phrasing (should HIT own group) + every novel.
query_idx = [i for i in range(N) if i not in seed_set]
n_para_q = sum(1 for i in query_idx if is_para(groups[i]))
n_novel_q = sum(1 for i in query_idx if not is_para(groups[i]))


def build_lsh(seed_indices, k, bands, band_bits, rng):
    """Banded-LSH over the ternary signatures. Each band = a random subset of
    `band_bits` dims of the FULL D space; a bucket key = the tuple of signature
    values (from {-1,0,+1}) on those dims. Two vectors share a band iff they agree
    on all band dims (including agreeing that a dim is NOT in either's top-K -> 0).
    Returns (band_dim_lists, list-of-{bucketkey->[seed_idx]})."""
    band_dims = [rng.choice(D, size=band_bits, replace=False) for _ in range(bands)]
    tables = [dict() for _ in range(bands)]
    sigs = {i: signature(X[i], k)[0] for i in seed_indices}
    for b in range(bands):
        dims = band_dims[b]
        for i in seed_indices:
            key = tuple(int(x) for x in sigs[i][dims])
            tables[b].setdefault(key, []).append(i)
    return band_dims, tables


def candidates(qi, k, band_dims, tables):
    sig = signature(X[qi], k)[0]
    cand = set()
    for b, dims in enumerate(band_dims):
        key = tuple(int(x) for x in sig[dims])
        for si in tables[b].get(key, ()):
            cand.add(si)
    return cand


def run_sim(k, tau, bands, band_bits, seed_rng=0):
    rng = np.random.default_rng(seed_rng)
    band_dims, tables = build_lsh(seeds, k, bands, band_bits, rng)

    true_hit = 0     # para query served its OWN group seed
    false_hit = 0    # any query served a WRONG group (para->other, or novel->any)
    miss = 0         # served nothing
    saved_ms = 0.0
    n_candidates = 0

    for qi in query_idx:
        cand = candidates(qi, k, band_dims, tables)
        n_candidates += len(cand)
        # VERIFY: best full-cosine candidate above tau wins; else MISS.
        best_si, best_c = None, -1.0
        for si in cand:
            c = cos(X[qi], X[si])
            if c > best_c:
                best_c, best_si = c, si
        served = best_si if (best_si is not None and best_c >= tau) else None

        if served is None:
            miss += 1
            continue
        served_group = groups[served]
        if is_para(groups[qi]) and served_group == groups[qi]:
            true_hit += 1
            # a hit skips the dot for the answer length (use served seed's tok_len as
            # the precomputed-answer proxy; the query itself would also cost prefill,
            # but the SERVED savings is the answer-token dots we never run).
            saved_ms += DOT_MS_PER_TOKEN * tok_len[served]
        else:
            false_hit += 1

    return dict(
        k=k, tau=tau, bands=bands, band_bits=band_bits,
        true_hit=true_hit, false_hit=false_hit, miss=miss,
        n_para_q=n_para_q, n_novel_q=n_novel_q,
        true_hit_rate=true_hit / max(n_para_q, 1),
        false_hit_rate=false_hit / max(len(query_idx), 1),
        avg_candidates=n_candidates / max(len(query_idx), 1),
        saved_ms=saved_ms,
    )


print(f"corpus: N={N}  paraphrase-groups={len(para_groups)}  seeds={len(seeds)}")
print(f"queries: {len(query_idx)}  (paraphrase={n_para_q}, novel={n_novel_q})\n")

# ---- report the raw separation the LSH must exploit --------------------------
within, across = [], []
for i, j in itertools.combinations(range(N), 2):
    c = cos(X[i], X[j])
    if groups[i] == groups[j] and is_para(groups[i]):
        within.append(c)
    else:
        across.append(c)
within, across = np.array(within), np.array(across)
print("full-cosine separation (context for tau):")
print(f"  within-group  mean={within.mean():.3f}  min={within.min():.3f}")
print(f"  across-group  mean={across.mean():.3f}  max={across.max():.3f}\n")

# ---- SWEEP ------------------------------------------------------------------
# Banded LSH: more bands => higher recall (more chances to collide) but more
# candidates to verify; band_bits controls bucket selectivity. We sweep K, tau,
# and the LSH (bands, band_bits) and pick the max true-hit at false-hit == 0.
print(f"{'K':>4} {'bands':>5} {'bits':>4} {'tau':>5} "
      f"{'trueHit':>8} {'falseHit':>9} {'miss':>5} {'avgCand':>8} {'savedMs':>9}")
print("-" * 66)

results = []
for k in (50, 64, 128):
    for bands in (8, 16, 24, 32):
        for band_bits in (8, 12, 16):
            for tau in (0.65, 0.70, 0.72, 0.75, 0.80):
                r = run_sim(k, tau, bands, band_bits)
                results.append(r)

# Print a readable subset: for each (K,tau) the best LSH by true-hit @ false-hit==0.
for k in (50, 64, 128):
    for tau in (0.70, 0.72, 0.75):
        cand = [r for r in results if r["k"] == k and r["tau"] == tau
                and r["false_hit"] == 0]
        pool = cand if cand else [r for r in results if r["k"] == k and r["tau"] == tau]
        best = max(pool, key=lambda r: (r["false_hit"] == 0, r["true_hit"], -r["avg_candidates"]))
        print(f"{best['k']:>4} {best['bands']:>5} {best['band_bits']:>4} {best['tau']:>5.2f} "
              f"{best['true_hit']:>3}/{best['n_para_q']:<4} "
              f"{best['false_hit']:>3}/{len(query_idx):<5} {best['miss']:>5} "
              f"{best['avg_candidates']:>8.2f} {best['saved_ms']:>9.0f}")

# ---- BEST OPERATING POINT: max true-hit with false-hit == 0 -----------------
zero_fp = [r for r in results if r["false_hit"] == 0]
best = max(zero_fp, key=lambda r: (r["true_hit"], -r["avg_candidates"], -r["k"]))
print("\n=== BEST OPERATING POINT (max true-hit @ false-hit == 0) ===")
print(f"  K={best['k']}  tau={best['tau']}  LSH bands={best['bands']} band_bits={best['band_bits']}")
print(f"  TRUE  hit-rate = {best['true_hit']}/{best['n_para_q']} = {best['true_hit_rate']*100:.1f}%  (paraphrase queries served their OWN group)")
print(f"  FALSE hit-rate = {best['false_hit']}/{len(query_idx)} = {best['false_hit_rate']*100:.2f}%  (post-verify; correctness gate)")
print(f"  misses         = {best['miss']}/{len(query_idx)}")
print(f"  avg candidates verified/query = {best['avg_candidates']:.2f}")

# tok/s-equivalent saved per hit
if best["true_hit"] > 0:
    avg_saved_per_hit = best["saved_ms"] / best["true_hit"]
    avg_ans_toks = avg_saved_per_hit / DOT_MS_PER_TOKEN
    print(f"\n  compute saved: total {best['saved_ms']:.0f} ms of lm_head-dot across {best['true_hit']} hits")
    print(f"  per hit: ~{avg_saved_per_hit:.0f} ms  (~{avg_ans_toks:.1f} answer-token dots @ {DOT_MS_PER_TOKEN:.0f} ms/token skipped)")
    print(f"  a served hit returns in O(cosine over {best['avg_candidates']:.1f} cands) ~= microseconds vs {avg_saved_per_hit:.0f} ms -> ~{avg_saved_per_hit/0.05:.0f}x on the served tokens")

# ---- also: what does a NAIVE verify-only cache (no LSH, brute cosine) get? ---
print("\n=== reference: brute-force verify-only (no LSH; cosine vs ALL seeds) ===")
for tau in (0.70, 0.72, 0.75):
    th = fh = ms = 0
    saved = 0.0
    for qi in query_idx:
        best_si, best_c = None, -1.0
        for si in seeds:
            c = cos(X[qi], X[si])
            if c > best_c:
                best_c, best_si = c, si
        served = best_si if best_c >= tau else None
        if served is None:
            ms += 1
        elif is_para(groups[qi]) and groups[served] == groups[qi]:
            th += 1; saved += DOT_MS_PER_TOKEN * tok_len[served]
        else:
            fh += 1
    print(f"  tau={tau:.2f}:  trueHit={th}/{n_para_q}  falseHit={fh}/{len(query_idx)}  miss={ms}  saved={saved:.0f}ms")
